mapper.select:
SELECT 
FROM test_run
WHERE deleted_at IS NULL

    AND project_id = #{projectId}


    AND status = #{status}

ORDER BY created_at DESC, name ASC

SELECT 
FROM test_run
WHERE project_id = #{projectId}
  AND created_by = #{createdBy}
  AND idempotency_key = #{idempotencyKey}
  AND deleted_at IS NULL

SELECT id, run_id, step_order, step_key, step_name, stage, step_type,
       status, started_at, finished_at, error_code, error_message
FROM test_run_step
WHERE run_id = #{runId}
  AND id = #{stepId}

SELECT id, run_id, step_order, step_key, step_name, stage, step_type,
       status, started_at, finished_at, error_code, error_message
FROM test_run_step
WHERE run_id = #{runId}
  AND step_key = #{stepKey}

SELECT e.id,
       e.run_id,
       e.step_id,
       s.step_key,
       e.event_type,
       e.source,
       CAST(e.payload_jsonb AS TEXT) AS payload_jsonb,
       e.occurred_at
FROM test_run_event e
LEFT JOIN test_run_step s ON s.id = e.step_id
WHERE e.run_id = #{runId}

    AND e.step_id = #{stepId}


    AND e.event_type = #{eventType}


    AND (e.occurred_at, e.id) > (
        SELECT cursor_event.occurred_at, cursor_event.id
        FROM test_run_event cursor_event
        WHERE cursor_event.run_id = #{runId}
          AND cursor_event.id = #{cursorEventId}
    )

ORDER BY e.occurred_at ASC, e.id ASC
LIMIT #{limit}

SELECT COUNT(*)
FROM runner_agent_trace
WHERE run_id = #{runId}
